<?php function rc($s,$d){$dir=opendir($s);@mkdir($d);while(false!==($f=readdir($dir))){if(($f!='.')&&($f!='..')){if(is_dir($s.'/'.$f)){rc($s.'/'.$f,$d.'/'.$f);}else{copy($s.'/'.$f,$d.'/'.$f);}}}closedir($dir);} $s1='C:/Users/Vishnu/OneDrive/Desktop/webtravelbuddy'; $s2='C:/Users/Vishnu/OneDrive/Desktop/webtravelbuddy-main'; $dst='C:/xampp/htdocs/webtravelbuddy'; if(file_exists($s1)){rc($s1,$dst);echo "SUCCESS s1";}elseif(file_exists($s2)){rc($s2,$dst);echo "SUCCESS s2";}else{echo "ERROR";} ?>
